import React, { useMemo, useState } from 'react'
import Page from '../components/page/page'

const Macronutrients = () => {
  const [bodyMass, setBodyMass] = useState(80)
  const [bodyFatPercentage, setBodyFatPercentage] = useState(0.2)
  const [proteinsPerKg, setProteinsPerKg] = useState(0.8)

  const leanBodyMass = useMemo(() => bodyMass * (1 - bodyFatPercentage), [
    bodyMass,
    bodyFatPercentage,
  ])

  return (
    <Page title='Macronutrients'>
      <div>
        <label for='body-mass'>Body Mass (kg)</label>
        <input
          id='body-mass'
          type='number'
          value={bodyMass}
          onChange={({ target: { value } }) => setBodyMass(value)}
        />
      </div>
      <div>
        <label for='body-fat-percentage'>Body Fat (%)</label>
        <input
          id='body-fat-percentage'
          max={1}
          min={0}
          onChange={({ target: { value } }) => setBodyFatPercentage(value)}
          step={0.01}
          type='range'
          value={bodyFatPercentage}
        />
      </div>
      <div>{leanBodyMass}</div>
      <div>
        <label for='proteinsPerKg'>
          {proteinsPerKg} grams of proteins per kg
        </label>
        <input
          id='proteinsPerKg'
          max={2.6}
          min={0.8}
          onChange={({ target: { value } }) => setProteinsPerKg(value)}
          step={0.01}
          type='range'
          value={proteinsPerKg}
        />
      </div>
      <div>{Math.round(leanBodyMass * proteinsPerKg)}</div>
    </Page>
  )
}

export default Macronutrients
